import {
  Box,
  Paper,
  Typography,
  Stack,
  Button,
  IconButton,
  Chip,
  Tooltip,
  Alert,
  Skeleton,
  alpha,
  useTheme,
  useMediaQuery,
  Drawer,
  Card,
  CardContent,
  TextField,
  Fade,
  Grow,
  Snackbar
} from '@mui/material';
import {
  ChevronLeft as ChevronLeftIcon,
  ChevronRight as ChevronRightIcon,
  Today as TodayIcon,
  Event as EventIcon,
  CheckCircle as CheckCircleIcon,
  Pending as PendingIcon,
  Cancel as CancelIcon,
  Schedule as ScheduleIcon,
  Search as SearchIcon,
  Close as CloseIcon,
  CalendarMonth as CalendarMonthIcon,
  ViewAgenda as ViewAgendaIcon,
  AccessTime as AccessTimeIcon,
  ArrowForward as ArrowForwardIcon,
  Refresh as RefreshIcon,
  LocationOn as LocationIcon,
  Assignment as AssignmentIcon
} from '@mui/icons-material';
import { 
  format, 
  startOfMonth, 
  endOfMonth, 
  eachDayOfInterval, 
  isSameMonth, 
  isSameDay, 
  addMonths, 
  subMonths, 
  getDay, 
  isToday 
} from 'date-fns';
import api from '../../../services/api';
import { useSelector as useAppSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';

// ==================== Constants ====================
const CALENDAR_VIEWS = {
  MONTH: 'month',
  AGENDA: 'agenda'
};

const CACHE_DURATION = 5 * 60 * 1000; // 5 minutes
const CACHE_KEY = 'calendar_meetings_cache';

// ==================== Safe Helpers ====================
const safeDate = (dateValue) => {
  try {
    if (!dateValue) return null;
    const date = new Date(dateValue);
    return isNaN(date.getTime()) ? null : date;
  } catch {
    return null;
  }
};

const safeFormat = (dateValue, formatStr = 'h:mm a') => {
  const date = safeDate(dateValue);
  if (!date) return 'TBD';
  try {
    return format(date, formatStr);
  } catch {
    return 'TBD';
  }
};

// IMPORTANT: Extract meeting from action item or direct meeting
const extractMeeting = (item) => {
  if (!item) return null;
  // If the item has a meeting property (action item from API)
  if (item.meeting) return item.meeting;
  // If it's a direct meeting object
  return item;
};

const getSafeTitle = (item) => {
  const meeting = extractMeeting(item);
  return (meeting?.title || meeting?.topic || 'Untitled Meeting').trim();
};

const getMeetingStatusConfig = (status) => {
  let code = '';

  if (typeof status === 'string') {
    code = status.toLowerCase();
  } else if (status && typeof status === 'object') {
    code = (status.code || status.name || status.short_name || '').toLowerCase();
  }

  if (code.includes('completed') || code.includes('finished') || code.includes('done')) {
    return { label: 'Completed', color: 'success', icon: <CheckCircleIcon fontSize="small" /> };
  }
  if (code.includes('in_progress') || code.includes('ongoing') || code.includes('started')) {
    return { label: 'In Progress', color: 'info', icon: <PendingIcon fontSize="small" /> };
  }
  if (code.includes('cancelled') || code.includes('canceled') || code.includes('cancel')) {
    return { label: 'Cancelled', color: 'error', icon: <CancelIcon fontSize="small" /> };
  }
  if (code.includes('scheduled')) {
    return { label: 'Scheduled', color: 'warning', icon: <ScheduleIcon fontSize="small" /> };
  }

  return { label: 'Draft', color: 'default', icon: <EventIcon fontSize="small" /> };
};

const formatTimeRange = (startDate, endDate) => {
  const start = safeFormat(startDate);
  if (!endDate) return start;
  return `${start} - ${safeFormat(endDate)}`;
};

// Cache Helpers
const getCachedData = () => {
  try {
    const cached = localStorage.getItem(CACHE_KEY);
    const timestamp = localStorage.getItem(`${CACHE_KEY}_time`);
    if (cached && timestamp && (Date.now() - parseInt(timestamp)) < CACHE_DURATION) {
      const parsed = JSON.parse(cached);
      // Restore dates
      return parsed.map(item => ({
        ...item,
        meeting: item.meeting ? {
          ...item.meeting,
          start_date: item.meeting.start_date ? new Date(item.meeting.start_date) : null,
          end_date: item.meeting.end_date ? new Date(item.meeting.end_date) : null
        } : null
      }));
    }
  } catch (e) {
    console.error('Cache read failed:', e);
  }
  return null;
};

const setCachedData = (data) => {
  try {
    localStorage.setItem(CACHE_KEY, JSON.stringify(data));
    localStorage.setItem(`${CACHE_KEY}_time`, Date.now().toString());
  } catch (e) {
    console.error('Cache write failed:', e);
  }
};

// ==================== Components ====================
const MeetingCard = React.memo(({ item, onClick }) => {
  const theme = useTheme();
  const isDarkMode = theme.palette.mode === 'dark';
  const meetingData = extractMeeting(item);
  const statusConfig = getMeetingStatusConfig(meetingData?.status);
  const startDate = safeDate(meetingData?.start_date);

  if (!meetingData) return null;

  return (
    <Grow in timeout={300}>
      <Card
        variant="outlined"
        onClick={() => onClick(item)}
        sx={{
          cursor: 'pointer',
          transition: 'transform 0.2s, box-shadow 0.2s',
          '&:hover': { transform: 'translateY(-2px)', boxShadow: 3 },
          bgcolor: isDarkMode ? '#1F2937' : '#FFFFFF',
          borderColor: isDarkMode ? '#374151' : '#E5E7EB'
        }}
      >
        <CardContent sx={{ p: 2, '&:last-child': { pb: 2 } }}>
          <Stack spacing={1.5}>
            <Stack direction="row" justifyContent="space-between" alignItems="flex-start">
              <Typography variant="subtitle2" fontWeight={700} sx={{ flex: 1, color: isDarkMode ? '#FFFFFF' : '#111827' }}>
                {getSafeTitle(item)}
              </Typography>
              <Chip
                size="small"
                label={statusConfig.label}
                color={statusConfig.color}
                icon={statusConfig.icon}
                sx={{ height: 22, fontSize: '0.7rem' }}
              />
            </Stack>

            <Stack direction="row" spacing={2} alignItems="center" flexWrap="wrap" sx={{ color: isDarkMode ? '#9CA3AF' : '#6B7280' }}>
              <EventIcon fontSize="small" />
              <Typography variant="caption">
                {startDate ? format(startDate, 'MMM d, yyyy') : 'Date TBD'}
              </Typography>
              <AccessTimeIcon fontSize="small" />
              <Typography variant="caption">
                {formatTimeRange(meetingData?.start_date, meetingData?.end_date)}
              </Typography>
            </Stack>
            
            {meetingData?.location && (
              <Stack direction="row" spacing={1} alignItems="center">
                <LocationIcon fontSize="small" sx={{ fontSize: 14, color: isDarkMode ? '#9CA3AF' : '#6B7280' }} />
                <Typography variant="caption" sx={{ color: isDarkMode ? '#9CA3AF' : '#6B7280' }}>
                  {meetingData.location}
                </Typography>
              </Stack>
            )}
            
            {item.description && (
              <Typography variant="caption" sx={{ color: isDarkMode ? '#9CA3AF' : '#6B7280' }}>
                Action: {item.description.length > 80 ? item.description.substring(0, 80) + '...' : item.description}
              </Typography>
            )}
          </Stack>
        </CardContent>
      </Card>
    </Grow>
  );
});

MeetingCard.displayName = 'MeetingCard';

const DayCell = React.memo(({ date, meetings, isCurrentMonth, onMeetingClick }) => {
  const theme = useTheme();
  const isDarkMode = theme.palette.mode === 'dark';
  const today = date ? isToday(date) : false;

  const dayMeetings = useMemo(() => {
    if (!Array.isArray(meetings) || !date) return [];
    return meetings.filter(item => {
      const meetingData = extractMeeting(item);
      const startDate = safeDate(meetingData?.start_date);
      return startDate && isSameDay(startDate, date);
    });
  }, [meetings, date]);

  if (!date) {
    return (
      <Box sx={{ 
        minHeight: 100, 
        border: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}`,
        bgcolor: isDarkMode ? '#111827' : '#F9FAFB'
      }} />
    );
  }

  return (
    <Box
      sx={{
        minHeight: 100,
        p: 0.5,
        bgcolor: isCurrentMonth ? (isDarkMode ? '#1F2937' : '#FFFFFF') : (isDarkMode ? '#111827' : '#F9FAFB'),
        border: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}`,
        position: 'relative',
        cursor: 'pointer',
        '&:hover': { bgcolor: alpha(isDarkMode ? '#A78BFA' : '#7C3AED', 0.05) }
      }}
      onClick={() => onMeetingClick(null, date)}
    >
      <Typography
        variant="caption"
        sx={{
          position: 'absolute',
          top: 4,
          right: 8,
          fontWeight: today ? 700 : 400,
          color: today ? '#F59E0B' : (isDarkMode ? '#9CA3AF' : '#6B7280'),
          bgcolor: today ? alpha('#F59E0B', 0.2) : 'transparent',
          px: 1,
          borderRadius: 1
        }}
      >
        {format(date, 'd')}
      </Typography>

      {dayMeetings.length > 0 && (
        <Stack spacing={0.5} sx={{ mt: 3 }}>
          {dayMeetings.slice(0, 3).map((item, idx) => {
            const meetingData = extractMeeting(item);
            const statusConfig = getMeetingStatusConfig(meetingData?.status);
            const startDate = safeDate(meetingData?.start_date);
            const timeStr = startDate ? format(startDate, 'h:mm a') : 'TBD';
            const titleStr = getSafeTitle(item);

            return (
              <Tooltip key={idx} title={`${titleStr} - ${statusConfig.label}`}>
                <Box
                  onClick={(e) => {
                    e.stopPropagation();
                    onMeetingClick(item);
                  }}
                  sx={{
                    p: 0.6,
                    borderRadius: 1,
                    fontSize: '0.72rem',
                    bgcolor: alpha(
                      statusConfig.color === 'success' ? '#10B981' :
                      statusConfig.color === 'info' ? '#3B82F6' :
                      statusConfig.color === 'error' ? '#EF4444' : '#F59E0B',
                      0.15
                    ),
                    color: isDarkMode ? '#D1D5DB' : '#374151',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    cursor: 'pointer',
                    '&:hover': { opacity: 0.85 }
                  }}
                >
                  {timeStr} — {titleStr.length > 22 ? titleStr.substring(0, 22) + '...' : titleStr}
                </Box>
              </Tooltip>
            );
          })}
          {dayMeetings.length > 3 && (
            <Typography variant="caption" sx={{ color: 'text.secondary', pl: 0.5 }}>
              +{dayMeetings.length - 3} more
            </Typography>
          )}
        </Stack>
      )}
    </Box>
  );
});

DayCell.displayName = 'DayCell';

