// ==================== Main Component ====================
const MeetingCalendar = ({ userId }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const isDarkMode = theme.palette.mode === 'dark';
  const navigate = useNavigate();

  const [currentDate, setCurrentDate] = useState(new Date());
  const [view, setView] = useState(CALENDAR_VIEWS.MONTH);
  const [meetings, setMeetings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(null);

  const abortControllerRef = useRef(null);
  const currentUser = useAppSelector(state => state.auth?.user);

  // Fetch data - extract meetings from action items
  const fetchData = useCallback(async (forceRefresh = false) => {
    if (!currentUser?.email) {
      setLoading(false);
      return;
    }

    // Check cache
    if (!forceRefresh) {
      const cached = getCachedData();
      if (cached && cached.length > 0) {
        setMeetings(cached);
        setLoading(false);
      }
    }

    // Cancel previous request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();

    setRefreshing(true);
    setError(null);

    try {
      // First, try to get action items (which contain meeting info)
      const response = await api.get('/action-tracker/meetings/participant/action-items', {
        params: {
          email: currentUser.email,
          upcoming_only: false,
          overdue_only: false,
          include_completed: true,
          limit: 100,
        },
        signal: abortControllerRef.current.signal,
      });

      // Extract the action items from response
      let actionItems = [];
      if (response.data?.action_items) {
        actionItems = response.data.action_items;
      } else if (Array.isArray(response.data)) {
        actionItems = response.data;
      }

      // Each action item contains a meeting object - extract unique meetings
      const uniqueMeetings = new Map();
      
      actionItems.forEach(item => {
        if (item.meeting && item.meeting.id) {
          // Store meeting by ID to avoid duplicates
          if (!uniqueMeetings.has(item.meeting.id)) {
            uniqueMeetings.set(item.meeting.id, {
              ...item.meeting,
              start_date: item.meeting.start_date,
              end_date: item.meeting.end_date
            });
          }
        }
      });

      const meetingsList = Array.from(uniqueMeetings.values());
      
      setMeetings(meetingsList);
      setCachedData(meetingsList);
    } catch (err) {
      if (err.name === 'CanceledError' || err.code === 'ERR_CANCELED') {
        console.log('Request canceled');
        return;
      }
      console.error('Error fetching data:', err);
      
      let errorMessage = 'Failed to load meetings.';
      if (err.response?.data?.detail) {
        errorMessage = err.response.data.detail;
      } else if (err.message) {
        errorMessage = err.message;
      }
      setError(errorMessage);
    } finally {
      setRefreshing(false);
      setLoading(false);
    }
  }, [currentUser?.email]);

  useEffect(() => {
    fetchData();
    
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [fetchData]);

  const handleRefresh = () => fetchData(true);

  const getDaysInMonth = useCallback(() => {
    const start = startOfMonth(currentDate);
    const end = endOfMonth(currentDate);
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const getMeetingsForDate = useCallback((date) => {
    if (!date || !Array.isArray(meetings)) return [];
    return meetings.filter(meeting => {
      if (!meeting?.start_date) return false;
      const meetingDate = safeDate(meeting.start_date);
      return meetingDate && isSameDay(meetingDate, date);
    });
  }, [meetings]);

  const goToPrevious = () => setCurrentDate(prev => subMonths(prev, 1));
  const goToNext = () => setCurrentDate(prev => addMonths(prev, 1));
  const goToToday = () => setCurrentDate(new Date());

  const handleMeetingClick = (item) => {
    setSelectedItem(item);
    setDetailsOpen(true);
  };

  const handleViewFullDetails = () => {
    if (selectedItem) {
      const meetingId = selectedItem.id;
      if (meetingId) {
        setDetailsOpen(false);
        navigate(`/action-tracker/meetings/${meetingId}`);
      }
    }
  };

  // Filter meetings by search term
  const filteredMeetings = useMemo(() => {
    if (!searchTerm) return meetings;
    const term = searchTerm.toLowerCase();
    return meetings.filter(meeting => 
      (meeting?.title || '').toLowerCase().includes(term) ||
      (meeting?.topic || '').toLowerCase().includes(term) ||
      (meeting?.location || '').toLowerCase().includes(term)
    );
  }, [meetings, searchTerm]);

  // Stats
  const stats = useMemo(() => {
    const now = new Date();
    const nowDate = new Date();
    return {
      total: filteredMeetings.length,
      today: filteredMeetings.filter(meeting => {
        const startDate = safeDate(meeting?.start_date);
        return startDate && isSameDay(startDate, nowDate);
      }).length,
      upcoming: filteredMeetings.filter(meeting => {
        const startDate = safeDate(meeting?.start_date);
        return startDate && startDate > nowDate;
      }).length
    };
  }, [filteredMeetings]);

  if (loading) {
    return <LoadingSkeleton />;
  }

  if (error && meetings.length === 0) {
    return (
      <Box sx={{ p: 3 }}>
        <Alert 
          severity="error" 
          action={
            <Button color="inherit" size="small" onClick={handleRefresh}>
              Retry
            </Button>
          }
        >
          {error}
        </Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ height: '100%', p: isMobile ? 2 : 3 }}>
      {/* Header */}
      <Paper
        elevation={0}
        sx={{
          p: 2,
          mb: 3,
          borderRadius: 3,
          bgcolor: isDarkMode ? '#1F2937' : '#FFFFFF',
          border: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}`
        }}
      >
        <Stack direction={{ xs: 'column', sm: 'row' }} justifyContent="space-between" alignItems="center" spacing={2}>
          <Stack direction="row" spacing={1} alignItems="center">
            <CalendarMonthIcon sx={{ color: isDarkMode ? '#A78BFA' : '#7C3AED' }} />
            <Typography variant="h5" fontWeight={700} sx={{ color: isDarkMode ? '#FFFFFF' : '#111827' }}>
              My Meetings Calendar
            </Typography>
            <Chip
              label={`${stats.total} meeting${stats.total !== 1 ? 's' : ''}`}
              size="small"
              sx={{ bgcolor: isDarkMode ? '#7C3AED' : '#7C3AED', color: '#FFFFFF' }}
            />
            {stats.today > 0 && (
              <Chip label={`${stats.today} today`} color="warning" size="small" />
            )}
          </Stack>

          <Stack direction="row" spacing={1}>
            <TextField
              size="small"
              placeholder="Search meetings..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              sx={{ width: isMobile ? 150 : 200 }}
              InputProps={{
                startAdornment: <SearchIcon fontSize="small" sx={{ mr: 1, color: isDarkMode ? '#9CA3AF' : '#6B7280' }} />,
                endAdornment: searchTerm && (
                  <IconButton size="small" onClick={() => setSearchTerm('')}>
                    <CloseIcon fontSize="small" />
                  </IconButton>
                )
              }}
            />
            <Tooltip title="Refresh">
              <IconButton onClick={handleRefresh} disabled={refreshing}>
                <RefreshIcon className={refreshing ? 'spin' : ''} />
              </IconButton>
            </Tooltip>
          </Stack>
        </Stack>

        {/* Stats Row */}
        <Stack
          direction="row"
          spacing={2}
          sx={{ mt: 2, pt: 2, borderTop: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}` }}
        >
          <Chip icon={<EventIcon />} label={`Total: ${stats.total}`} variant="outlined" />
          <Chip icon={<ScheduleIcon />} label={`Upcoming: ${stats.upcoming}`} color="warning" variant="outlined" />
          <Chip icon={<CheckCircleIcon />} label={`Completed: ${meetings.filter(m => m.status === 'completed').length}`} color="success" variant="outlined" />
        </Stack>
      </Paper>

      {/* Controls */}
      <Paper
        elevation={0}
        sx={{
          p: 1,
          mb: 3,
          borderRadius: 3,
          bgcolor: isDarkMode ? '#1F2937' : '#FFFFFF',
          border: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}`
        }}
      >
        <Stack direction="row" justifyContent="space-between" alignItems="center">
          <Stack direction="row" spacing={1} alignItems="center">
            <IconButton onClick={goToPrevious}>
              <ChevronLeftIcon />
            </IconButton>
            <Typography variant="h6" sx={{ minWidth: 180, textAlign: 'center', color: isDarkMode ? '#FFFFFF' : '#111827' }}>
              {format(currentDate, 'MMMM yyyy')}
            </Typography>
            <IconButton onClick={goToNext}>
              <ChevronRightIcon />
            </IconButton>
          </Stack>

          <Button size="small" onClick={goToToday} startIcon={<TodayIcon />}>
            Today
          </Button>
        </Stack>
      </Paper>

      {/* Month View */}
      {view === CALENDAR_VIEWS.MONTH && filteredMeetings.length > 0 ? (
        <Paper
          elevation={0}
          sx={{
            borderRadius: 3,
            overflow: 'auto',
            bgcolor: isDarkMode ? '#1F2937' : '#FFFFFF',
            border: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}`
          }}
        >
          <Box sx={{ minWidth: 600 }}>
            {/* Weekday Headers */}
            <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', borderBottom: `1px solid ${isDarkMode ? '#374151' : '#E5E7EB'}` }}>
              {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map(day => (
                <Box key={day} sx={{ p: 2, textAlign: 'center', bgcolor: isDarkMode ? '#111827' : '#F9FAFB' }}>
                  <Typography variant="subtitle2" fontWeight={600} sx={{ color: isDarkMode ? '#D1D5DB' : '#4B5563' }}>
                    {day}
                  </Typography>
                </Box>
              ))}
            </Box>

            {/* Calendar Grid */}
            <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)' }}>
              {(() => {
                const days = getDaysInMonth();
                const startDay = getDay(startOfMonth(currentDate));
                const emptyDays = startDay === 0 ? 6 : startDay - 1;

                return [
                  ...Array.from({ length: emptyDays }).map((_, i) => (
                    <DayCell
                      key={`empty-${i}`}
                      date={null}
                      meetings={[]}
                      isCurrentMonth={false}
                      onMeetingClick={() => {}}
                    />
                  )),
                  ...days.map(day => (
                    <DayCell
                      key={day.toISOString()}
                      date={day}
                      meetings={filteredMeetings}
                      isCurrentMonth={isSameMonth(day, currentDate)}
                      onMeetingClick={handleMeetingClick}
                    />
                  ))
                ];
              })()}
            </Box>
          </Box>
        </Paper>
      ) : (
        <EmptyState searchTerm={searchTerm} onClearSearch={() => setSearchTerm('')} />
      )}

      {/* Details Drawer */}
      <Drawer
        anchor="right"
        open={detailsOpen}
        onClose={() => setDetailsOpen(false)}
        PaperProps={{
          sx: {
            width: { xs: '100%', sm: 480 },
            bgcolor: isDarkMode ? '#1F2937' : '#FFFFFF'
          }
        }}
      >
        {selectedItem && (
          <Box sx={{ p: 3 }}>
            <Stack direction="row" justifyContent="space-between" alignItems="center" mb={3}>
              <Typography variant="h6" fontWeight={700} sx={{ color: isDarkMode ? '#FFFFFF' : '#111827' }}>
                Meeting Details
              </Typography>
              <IconButton onClick={() => setDetailsOpen(false)}>
                <CloseIcon />
              </IconButton>
            </Stack>

            <Typography variant="h6" gutterBottom sx={{ color: isDarkMode ? '#FFFFFF' : '#111827' }}>
              {getSafeTitle(selectedItem)}
            </Typography>

            {selectedItem.start_date && (
              <Stack direction="row" spacing={1} alignItems="center" mt={2}>
                <EventIcon fontSize="small" sx={{ color: isDarkMode ? '#A78BFA' : '#7C3AED' }} />
                <Typography variant="body2" sx={{ color: isDarkMode ? '#D1D5DB' : '#4B5563' }}>
                  {safeFormat(selectedItem.start_date, 'EEEE, MMMM d, yyyy')}
                </Typography>
              </Stack>
            )}

            <Button
              variant="contained"
              fullWidth
              onClick={handleViewFullDetails}
              endIcon={<ArrowForwardIcon />}
              sx={{
                mt: 3,
                bgcolor: isDarkMode ? '#7C3AED' : '#7C3AED',
                '&:hover': { bgcolor: isDarkMode ? '#6D28D9' : '#6D28D9' }
              }}
            >
              View Full Meeting Details
            </Button>
          </Box>
        )}
      </Drawer>

      {/* Error Snackbar */}
      <Snackbar
        open={!!error}
        autoHideDuration={5000}
        onClose={() => setError(null)}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
      >
        <Alert severity="error" variant="filled" onClose={() => setError(null)}>
          {error}
        </Alert>
      </Snackbar>

      <style jsx>{`
        .spin {
          animation: spin 0.8s linear infinite;
        }
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </Box>
  );
};

export default MeetingCalendar;